def _resolve_dynamic_defaults(self, ctx: Context) -> None:
    """Resolve options whose ``default`` is a mapping of other
    option declarations to value maps (dynamic defaults). This runs
    after every parameter has consumed its command line, environment
    variable, and default map value, so the values being depended on
    are final.
    """
    params = self.get_params(ctx)

    for param in params:
        if not isinstance(param, Option) or not isinstance(param.default, dict):
            continue

        if param.name is None:
            continue

        if ctx.get_parameter_source(param.name) is not ParameterSource.DEFAULT:
            continue

        resolved = None

        for decl, value_map in param.default.items():
            source_param = next(
                (
                    p
                    for p in params
                    if decl in p.opts or decl in getattr(p, "secondary_opts", ())
                ),
                None,
            )

            if source_param is None or source_param.name is None:
                continue

            key = str(ctx.params.get(source_param.name))

            if key in value_map:
                resolved = value_map[key]

        if resolved is None:
            continue

        with augment_usage_errors(ctx, param=param):
            try:
                value = param.process_value(ctx, resolved)
            except Exception:
                if not ctx.resilient_parsing:
                    raise

                value = None

        if param.expose_value:
            ctx.params[param.name] = value

